#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    int s[2],v,f,sz;
    void init(int _v){
        v=_v,sz=1;
    }
}t[N];

int n,m,q,p[N];

void pushup(int x){
    t[x].sz=t[t[x].s[0]].sz+1+t[t[x].s[1]].sz;
}

void Rotate(int x){
    int y=t[x].f,z=t[y].f,k=(x==t[y].s[1]);
    t[z].s[y==t[z].s[1]]=x,t[x].f=z;
    t[y].s[k]=t[x].s[k^1],t[t[x].s[k^1]].f=y;
    t[x].s[k^1]=y,t[y].f=x;
    pushup(y),pushup(x);
}

void Splay(int x,int k){
    while(t[x].f!=k){
        int y=t[x].f,z=t[y].f;
        if(z!=k)
            if((x==t[y].s[1])^(y==t[z].s[1])) Rotate(x);
            else Rotate(y);
        Rotate(x);
    }
}

void Insert(int x,int u){
    Splay(x,0);
    int p=0;
    while(x) p=x,x=t[x].s[t[u].v>t[x].v];
    t[u].f=p;
    if(p) t[p].s[t[u].v>t[p].v]=u;
    Splay(u,0);
}

void dfs(int u,int x){
    if(t[u].s[0]) dfs(t[u].s[0],x);
    if(t[u].s[1]) dfs(t[u].s[1],x);
    t[u].s[0]=t[u].s[1]=0;
    t[u].sz=1;
    Insert(x,u);
}

int get_k(int x,int k){
    while(x){
        if(t[t[x].s[0]].sz>=k) x=t[x].s[0];
        else if(t[t[x].s[0]].sz+1==k) return x;
        else k-=t[t[x].s[0]].sz+1,x=t[x].s[1];
    }
    return -1;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&p[i]);
        t[i].init(p[i]);
    }
    while(m--){
        int u,v;
        scanf("%d%d",&u,&v);
        if(u==v) continue;
        Splay(u,0);
        Splay(v,0);
        if(t[u].f) continue;
        if(t[u].sz>t[v].sz)
            swap(u,v);
        dfs(u,v);
    }
    scanf("%d",&q);
    while(q--){
        char op[2];
        int x,y;
        scanf("%s%d%d",op,&x,&y);
        if(*op=='B'){
            Splay(x,0);
            Splay(y,0);
            if(t[x].f || x==y) continue;
            if(t[x].sz>t[y].sz)
                swap(x,y);
            dfs(x,y);
        }else{
            Splay(x,0);
            if(y>t[x].sz)
                puts("-1");
            else{
                int ans=get_k(x,y);
                Splay(ans,0);
                printf("%d\n",ans);
            }
        }
    }
    return 0;
}
